import React, { useEffect, useState } from "react";
import './AccountSettings.css';
import defaultProfileImage from '../../pages/user-profile-icon-symbol-template-free-vector.jpg';

const AccountSettings = () => {
    const [user, setUser] = useState(null);
    const [error, setError] = useState("");
    const [successMessage, setSuccessMessage] = useState("");

    useEffect(() => {
        const storedUser = JSON.parse(localStorage.getItem("user"));
        if (!storedUser || !storedUser.email) {
            setError("🚨 Aucun utilisateur trouvé. Veuillez vous reconnecter.");
        } else {
            setUser(storedUser);
        }
    }, []);

    const handleInputChange = (e) => {
        const { name, value } = e.target;
        setUser((prevUser) => ({
            ...prevUser,
            [name]: value,
        }));
    };

    const handleImageUpload = (e) => {
        const file = e.target.files[0];
        if (file) {
            const reader = new FileReader();
            reader.onload = () => {
                setUser((prevUser) => ({
                    ...prevUser,
                    image: reader.result, // Stocke l’image en Base64
                }));
            };
            reader.readAsDataURL(file);
        }
    };

    const handleSaveChanges = async () => {
        if (!user) return;

        try {
            const response = await fetch(`http://localhost:5001/user/email/${user.email}`, {
                method: "PUT",
                headers: {
                    "Content-Type": "application/json",
                },
                body: JSON.stringify(user),
            });

            const data = await response.json();
            if (response.ok) {
                setSuccessMessage("✅ Modifications enregistrées avec succès !");
                localStorage.setItem("user", JSON.stringify(user));
            } else {
                setError("🚨 Échec de la mise à jour.");
            }
        } catch (err) {
            setError("❌ Erreur de mise à jour.");
        }
    };

    return (
        <div className='accountsettings'>
            <h1 className='mainhead1'>Personal Information</h1>
            {error && <p className="error-message">{error}</p>}
            {successMessage && <p className="success-message">{successMessage}</p>}

            <div className="profile-image-container">
                <img src={user?.image || defaultProfileImage} alt="Profile" className="profile-image" />
            </div>

            <input type="file" accept="image/*" onChange={handleImageUpload} className="upload-input" />

            <div className='form'>
                <div className='form-group'>
                    <label>Your Name</label>
                    <input type='text' name='name' value={user?.name || ''} onChange={handleInputChange} />
                </div>

                <div className='form-group'>
                    <label>Email</label>
                    <input type='email' name='email' value={user?.email || ''} disabled />
                </div>
            </div>

            <button className='mainbutton1' onClick={handleSaveChanges}>Save Changes</button>
        </div>
    );
};

export default AccountSettings;
